"""Агентский loop: tool-calling через OpenAI-совместимый API (Ollama)."""

from __future__ import annotations

import json
import sys
from dataclasses import dataclass, field
from typing import Any

from openai import OpenAI

from .config import Config, load_config
from .db import OracleClient
from .prompts import build_system_prompt
from .tools import TOOL_SCHEMAS, ToolContext, dispatch_tool


@dataclass
class AgentResult:
    answer: str
    supporting_data: dict[str, Any] = field(default_factory=dict)
    trace: list[dict[str, Any]] = field(default_factory=list)
    success: bool = True
    error: str | None = None


def _log(msg: str) -> None:
    """Диагностика в stderr (stdout зарезервирован под финальный ответ)."""
    print(f"[agent] {msg}", file=sys.stderr, flush=True)


# Числовая эвристика — должна различать «103 клиента» (валидный ответ) от
# «Запрос #1 выполнен» / «Цикл завершён (шаг 4/8).» (служебная фраза).
# Требуем последовательность >=3 цифр подряд ИЛИ форматированное число с
# разделителем (1 234, 12,5, 1.5M и т.п.).
_NUMBER_RE = __import__("re").compile(
    r"\d{3,}"               # 3+ цифры подряд: 103, 1206, 345802507
    r"|\d+[.,]\d+"          # десятичные: 12.5, 1,5
    r"|\d+\s\d{3}"          # с пробельным разделителем: 1 234, 345 802 507
)


def _content_has_numbers(content: str | None) -> bool:
    """
    True если текст содержит цифровое значение, похожее на финансовый ответ.

    Намеренно НЕ считаем одиночные 1-2-цифровые числа (года, номера шагов)
    «контентом» — иначе фразы вида «Запрос #1 выполнен» или «шаг 4/8»
    обходят PREMORTEM #1 mitigation.
    """
    if not content:
        return False
    return bool(_NUMBER_RE.search(content))


def _tool_calls_to_dicts(tool_calls: list[Any]) -> list[dict[str, Any]]:
    """Сериализует openai SDK tool_calls для повторной отправки в messages."""
    out: list[dict[str, Any]] = []
    for tc in tool_calls or []:
        out.append(
            {
                "id": tc.id,
                "type": "function",
                "function": {
                    "name": tc.function.name,
                    "arguments": tc.function.arguments or "{}",
                },
            }
        )
    return out


class Text2SQLAgent:
    def __init__(self, cfg: Config | None = None, db: OracleClient | None = None):
        self.cfg = cfg or load_config()
        self.client = OpenAI(
            base_url=self.cfg.api_url,
            api_key=self.cfg.api_key,
            timeout=self.cfg.llm_timeout_s,
        )
        self.db = db or OracleClient(self.cfg)

    def run(self, question: str) -> AgentResult:
        # CRITICAL: db.connect() и весь loop оборачиваем в try/except, чтобы
        # Oracle-down / Ollama-down не приводили к traceback'у на stdout.
        try:
            self.db.connect()
        except Exception as e:
            err = f"Oracle недоступен: {e.__class__.__name__}: {e}"
            _log(err)
            return AgentResult(
                answer=(
                    "Не удалось подключиться к базе данных. "
                    "Проверьте, что Oracle XE запущен и креды в .env корректны. "
                    f"Подробности: {e}"
                ),
                success=False,
                error=err,
            )
        try:
            return self._run_loop(question)
        except Exception as e:
            # Финальная страховка: любая необработанная ошибка превращается
            # в AgentResult, а не traceback.
            err = f"Внутренняя ошибка агента: {e.__class__.__name__}: {e}"
            _log(err)
            return AgentResult(
                answer=(
                    "Не удалось получить ответ из-за внутренней ошибки. "
                    f"Подробности: {e}"
                ),
                success=False,
                error=err,
            )
        finally:
            try:
                self.db.close()
            except Exception as e:
                _log(f"db.close() failed: {e}")

    def _run_loop(self, question: str) -> AgentResult:
        ctx = ToolContext(db=self.db)
        messages: list[dict[str, Any]] = [
            {"role": "system", "content": build_system_prompt()},
            {"role": "user", "content": question},
        ]
        trace: list[dict[str, Any]] = []

        for step in range(self.cfg.max_agent_steps):
            _log(f"шаг {step + 1}/{self.cfg.max_agent_steps}: запрос к LLM")
            try:
                resp = self.client.chat.completions.create(
                    model=self.cfg.sql_model,
                    messages=messages,
                    tools=TOOL_SCHEMAS,
                    tool_choice="auto",
                    temperature=0.1,
                )
            except Exception as e:
                err = f"LLM API error: {e.__class__.__name__}: {e}"
                _log(err)
                return AgentResult(
                    answer=f"Не удалось получить ответ: {err}",
                    success=False,
                    error=err,
                    trace=trace,
                )

            msg = resp.choices[0].message
            tool_calls = list(msg.tool_calls or [])

            # Сохраняем assistant-сообщение в history (с tool_calls, если есть).
            asst_msg: dict[str, Any] = {"role": "assistant", "content": msg.content or ""}
            if tool_calls:
                asst_msg["tool_calls"] = _tool_calls_to_dicts(tool_calls)
            messages.append(asst_msg)
            trace.append(
                {
                    "step": step + 1,
                    "assistant_content": msg.content,
                    "tool_calls": [
                        {
                            "name": tc.function.name,
                            "args": tc.function.arguments,
                        }
                        for tc in tool_calls
                    ],
                }
            )

            if not tool_calls:
                content = (msg.content or "").strip()
                # Если модель ответила без tool-calls, но был успешный SQL, и в
                # её ответе нет конкретики — принудительно формируем ответ из
                # данных через отдельный LLM-вызов.
                if ctx.last_result is not None and not _content_has_numbers(content):
                    _log("LLM завершила без final_answer и без чисел — finalize по данным")
                    final = self._finalize_from_data(question, ctx)
                    return AgentResult(
                        answer=final,
                        trace=trace,
                        success=True,
                    )
                _log("LLM завершила без tool-calls — возвращаем content как финальный ответ")
                return AgentResult(
                    answer=content or "(пустой ответ)",
                    trace=trace,
                    success=True,
                )

            # Выполняем все tool_calls последовательно. Если встретился
            # final_answer — выполняем его, и для остальных tool_calls в
            # этой response отдаём «accepted: false» без побочных DB-эффектов.
            for tc in tool_calls:
                name = tc.function.name
                args = tc.function.arguments or "{}"
                _log(f"  tool_call: {name}({args[:200]}{'...' if len(args) > 200 else ''})")
                if ctx.final is not None and name != "final_answer":
                    # final_answer уже принят — больше ничего не выполняем,
                    # чтобы не корраптить state и не делать лишних запросов в БД.
                    result_json = json.dumps(
                        {"skipped": True, "reason": "final_answer already accepted"},
                        ensure_ascii=False,
                    )
                else:
                    result_json = dispatch_tool(name, args, ctx)
                _log(f"  -> {result_json[:200]}{'...' if len(result_json) > 200 else ''}")
                messages.append(
                    {
                        "role": "tool",
                        "tool_call_id": tc.id,
                        "content": result_json,
                    }
                )

            if ctx.final is not None:
                _log("получен final_answer")
                return AgentResult(
                    answer=ctx.final.get("text", ""),
                    supporting_data=ctx.final.get("supporting_data", {}) or {},
                    trace=trace,
                    success=True,
                )

        # Лимит шагов исчерпан — пытаемся сформировать ответ из последнего результата.
        _log("превышен лимит шагов — формируем fallback-ответ")
        fallback = self._fallback_answer(ctx)
        return AgentResult(
            answer=fallback,
            trace=trace,
            success=False,
            error="max_agent_steps exceeded",
        )

    def _finalize_from_data(self, question: str, ctx: ToolContext) -> str:
        """
        Доформулировывает NL-ответ, если модель остановилась без `final_answer`.

        Использует response_model и подаёт ему last_sql + last_result, чтобы
        получить корректный ответ с цифрами.
        """
        if ctx.last_result is None:
            return "Не удалось получить данные для ответа."
        r = ctx.last_result
        data_blob = json.dumps(
            {
                "columns": r.columns,
                "rows": r.rows[:50],
                "row_count": r.row_count,
                "truncated": r.truncated,
            },
            ensure_ascii=False,
            default=str,
        )
        sys_msg = (
            "Ты — финансовый аналитик. Тебе дан результат SQL-запроса (JSON) "
            "и вопрос пользователя. Сформулируй краткий ответ на русском "
            "с конкретными числами из результата. Денежные значения — в рублях; "
            "крупные числа — с разделителями или с округлением до тыс./млн/млрд. "
            "Не выдумывай цифр, используй только то, что есть в данных."
        )
        usr_msg = (
            f"Вопрос пользователя: {question}\n\n"
            f"SQL: {ctx.last_sql}\n\n"
            f"Результат:\n{data_blob}\n\n"
            "Сформулируй финальный ответ."
        )
        try:
            resp = self.client.chat.completions.create(
                model=self.cfg.response_model,
                messages=[
                    {"role": "system", "content": sys_msg},
                    {"role": "user", "content": usr_msg},
                ],
                temperature=0.1,
            )
            return (resp.choices[0].message.content or "").strip() or self._fallback_answer(ctx)
        except Exception as e:
            _log(f"finalize error: {e}")
            return self._fallback_answer(ctx)

    def _fallback_answer(self, ctx: ToolContext) -> str:
        if ctx.last_result is None:
            return (
                "Не удалось получить ответ: модель не завершила работу за выделенное "
                "число шагов и не выполнила ни одного SQL-запроса."
            )
        r = ctx.last_result
        preview = json.dumps(
            {"columns": r.columns, "rows": r.rows[:5], "row_count": r.row_count},
            ensure_ascii=False,
            default=str,
        )
        return (
            "Не удалось завершить рассуждение в рамках лимита шагов. "
            f"Последний выполненный SQL: {ctx.last_sql!r}. "
            f"Результат (превью): {preview}"
        )

"""Реализации tool'ов для агента + JSON-схемы для OpenAI tool-calling."""

from __future__ import annotations

import json
from dataclasses import dataclass, field
from typing import Any

from .db import OracleClient, QueryResult
from .safe_sql import UnsafeSQLError, ensure_safe_select
from .schema import get_compact_schema

# ---------------------------------------------------------------------------
# OpenAI tool-schema (JSON-Schema) для function calling
# ---------------------------------------------------------------------------

