# ---------------------------------------------------------------------------
# Tool dispatcher
# ---------------------------------------------------------------------------


@dataclass
class ToolContext:
    """Состояние, общее между вызовами tool'ов в одной сессии."""

    db: OracleClient
    last_result: QueryResult | None = None
    last_sql: str | None = None
    final: dict[str, Any] | None = None
    history: list[dict[str, Any]] = field(default_factory=list)


def tool_inspect_schema(args: dict[str, Any], ctx: ToolContext) -> dict[str, Any]:
    table = (args.get("table") or "client_product").strip()
    try:
        return get_compact_schema(table)
    except ValueError as e:
        return {"error": str(e)}


def tool_execute_sql(args: dict[str, Any], ctx: ToolContext) -> dict[str, Any]:
    sql = args.get("sql", "")
    if not isinstance(sql, str) or not sql.strip():
        # Очищаем state даже на bad-args: следующий validate_result должен
        # говорить «нет данных», а не валидировать предыдущий результат.
        ctx.last_result = None
        ctx.last_sql = None
        return {"error": "Параметр 'sql' пустой или не строка."}
    # Defense-in-depth: проверяем safety тут же, до похода в БД.
    try:
        ensure_safe_select(sql)
    except UnsafeSQLError as e:
        # CRITICAL: при ошибке очищаем stale state, чтобы validate_result /
        # _finalize_from_data не использовали данные предыдущего успешного SQL.
        ctx.last_result = None
        ctx.last_sql = None
        return {"error": f"SQL отвергнут safety-фильтром: {e}"}
    try:
        result = ctx.db.execute_select(sql)
    except UnsafeSQLError as e:
        ctx.last_result = None
        ctx.last_sql = None
        return {"error": f"SQL отвергнут safety-фильтром: {e}"}
    except Exception as e:  # oracledb.DatabaseError и т.п.
        ctx.last_result = None
        ctx.last_sql = None
        return {"error": f"Ошибка выполнения SQL: {e.__class__.__name__}: {e}"}

    ctx.last_result = result
    ctx.last_sql = sql
    return {
        "columns": result.columns,
        "rows": result.rows,
        "row_count": result.row_count,
        "truncated": result.truncated,
    }


def _is_number(v: Any) -> bool:
    return isinstance(v, (int, float)) and not isinstance(v, bool)


def tool_validate_result(args: dict[str, Any], ctx: ToolContext) -> dict[str, Any]:
    exp = args.get("expectations") or {}
    if ctx.last_result is None:
        return {"ok": False, "issues": ["Нет результата для валидации — выполни SQL."]}

    res = ctx.last_result
    issues: list[str] = []

    min_rows = exp.get("min_rows")
    max_rows = exp.get("max_rows")
    if min_rows is not None and res.row_count < int(min_rows):
        issues.append(f"row_count={res.row_count} < min_rows={min_rows}")
    if max_rows is not None and res.row_count > int(max_rows):
        issues.append(f"row_count={res.row_count} > max_rows={max_rows}")

    if exp.get("expect_non_empty") and res.row_count == 0:
        issues.append("Результат пустой, а ожидался непустой.")

    col_idx = {c: i for i, c in enumerate(res.columns)}

    for col in exp.get("non_null_columns", []) or []:
        if col not in col_idx:
            issues.append(f"Столбец {col!r} отсутствует в результате (non_null_columns).")
            continue
        i = col_idx[col]
        n_null = sum(1 for row in res.rows if row[i] is None)
        if n_null:
            issues.append(f"В столбце {col!r} найдено NULL: {n_null} строк.")

    for col in exp.get("numeric_columns", []) or []:
        if col not in col_idx:
            issues.append(f"Столбец {col!r} отсутствует в результате (numeric_columns).")
            continue
        i = col_idx[col]
        non_num = sum(1 for row in res.rows if row[i] is not None and not _is_number(row[i]))
        if non_num:
            issues.append(f"В столбце {col!r} найдено нечисловых значений: {non_num}.")

    for col, rng in (exp.get("value_ranges") or {}).items():
        if col not in col_idx:
            issues.append(f"Столбец {col!r} отсутствует в результате (value_ranges).")
            continue
        i = col_idx[col]
        vmin = rng.get("min")
        vmax = rng.get("max")
        out_of_range = 0
        for row in res.rows:
            v = row[i]
            if v is None or not _is_number(v):
                continue
            if vmin is not None and v < vmin:
                out_of_range += 1
            elif vmax is not None and v > vmax:
                out_of_range += 1
        if out_of_range:
            issues.append(
                f"В столбце {col!r} {out_of_range} значений вне диапазона "
                f"[{vmin}, {vmax}]."
            )

    summary = {
        "row_count": res.row_count,
        "columns": res.columns,
        "truncated": res.truncated,
        "preview": res.rows[: min(3, res.row_count)],
    }
    return {"ok": not issues, "issues": issues, "summary": summary}


def tool_final_answer(args: dict[str, Any], ctx: ToolContext) -> dict[str, Any]:
    text = args.get("text") or ""
    supporting = args.get("supporting_data") or {}
    ctx.final = {"text": text, "supporting_data": supporting}
    return {"accepted": True}


TOOL_DISPATCH = {
    "inspect_schema": tool_inspect_schema,
    "execute_sql": tool_execute_sql,
    "validate_result": tool_validate_result,
    "final_answer": tool_final_answer,
}


def dispatch_tool(name: str, args_json: str, ctx: ToolContext) -> str:
    """Возвращает JSON-строку с результатом tool'а."""
    try:
        args = json.loads(args_json) if args_json else {}
    except json.JSONDecodeError as e:
        return json.dumps({"error": f"Невалидный JSON в arguments: {e}"})
    if not isinstance(args, dict):
        return json.dumps({"error": "arguments должны быть JSON-объектом."})

    fn = TOOL_DISPATCH.get(name)
    if fn is None:
        return json.dumps({"error": f"Неизвестный tool: {name!r}"})
    try:
        result = fn(args, ctx)
    except Exception as e:
        result = {"error": f"{e.__class__.__name__}: {e}"}
    return json.dumps(result, ensure_ascii=False, default=str)

"""Тонкая обёртка над oracledb с safety-фильтром и сериализацией результата."""

from __future__ import annotations

import datetime as _dt
import decimal
from dataclasses import dataclass, field
from typing import Any

import oracledb

from .config import Config
from .safe_sql import ensure_safe_select


@dataclass
class QueryResult:
    columns: list[str]
    rows: list[list[Any]]
    row_count: int
    truncated: bool = False
    notes: list[str] = field(default_factory=list)

    def to_dict(self) -> dict[str, Any]:
        return {
            "columns": self.columns,
            "rows": self.rows,
            "row_count": self.row_count,
            "truncated": self.truncated,
            "notes": self.notes,
        }


def _to_json_safe(value: Any) -> Any:
    """Конвертирует oracle типы в JSON-сериализуемые."""
    if value is None:
        return None
    if isinstance(value, (bool, int, str)):
        return value
    if isinstance(value, float):
        # Защита от NaN/Inf — JSON их не любит.
        if value != value or value in (float("inf"), float("-inf")):
            return None
        return value
    if isinstance(value, decimal.Decimal):
        # Сохраняем точность для крупных сумм через float; при потере точности — str.
        try:
            return float(value)
        except (OverflowError, ValueError):
            return str(value)
    if isinstance(value, (_dt.datetime, _dt.date)):
        return value.isoformat()
    if isinstance(value, bytes):
        try:
            return value.decode("utf-8")
        except UnicodeDecodeError:
            return value.hex()
    return str(value)


class OracleClient:
    """Подключение к Oracle XE, read-only выполнение SELECT."""

    def __init__(self, cfg: Config):
        self._cfg = cfg
        self._conn: oracledb.Connection | None = None

    def connect(self) -> None:
        if self._conn is not None:
            return
