def get_compact_schema(table: str = "client_product") -> dict[str, Any]:
    """
    Возвращает компактный JSON-описатель таблицы для LLM.

    Структура:
      {
        "table": "client_product",
        "description": "...",
        "fields": [
          {"name", "type", "description", "category", "is_key", ...}
        ],
        "sql_examples": [...]
      }
    """
    meta = get_table_metadata(table)
    fields_out: list[dict[str, Any]] = []
    for name, props in meta["fields"].items():
        fields_out.append(
            {
                "name": name,
                "type": props.get("type"),
                "category": props.get("category"),
                "description": (props.get("description") or "").strip(),
                "is_key": props.get("is_key", False),
                "aggregation_between_clients": props.get(
                    "aggregation_between_clients"
                ),
                "aggregation_between_month": props.get("aggregation_between_month"),
                "operation_currency": props.get("operation_currency"),
                "result_currency_equivalent": props.get("result_currency_equivalent"),
            }
        )

    return {
        "table": meta["table_name"],
        "description": meta["description"].strip(),
        "fields": fields_out,
        "sql_examples": meta.get("sql_examples", []),
    }


def format_schema_for_prompt(
    table: str = "client_product",
    n_examples: int = DEFAULT_EXAMPLES,
) -> str:
    """Plain-text форма схемы для встраивания в system prompt."""
    s = get_compact_schema(table)
    lines: list[str] = []
    lines.append(f"# Таблица: {s['table']}")
    lines.append("")
    lines.append(s["description"])
    lines.append("")
    lines.append("## Поля")
    by_cat: dict[str, list[dict[str, Any]]] = {}
    for f in s["fields"]:
        by_cat.setdefault(f["category"] or "—", []).append(f)
    for cat, fs in by_cat.items():
        lines.append(f"### {cat}")
        for f in fs:
            key = " [KEY]" if f.get("is_key") else ""
            lines.append(f"- `{f['name']}` ({f['type']}){key}: {f['description']}")
        lines.append("")

    if s["sql_examples"]:
        lines.append("## Примеры SQL (Oracle):")
        for ex in s["sql_examples"][:n_examples]:
            lines.append(f"Q: {ex['question']}")
            lines.append("SQL:")
            lines.append(ex["sql"].strip())
            lines.append("")
    return "\n".join(lines).strip()


